package org.eclipse.rdf4j.sail.lmdb.sketch.omni;

import org.apache.datasketches.common.SketchesArgumentException;

/**
 * Estimate returned by OmniSketch queries.
 *
 * <p>
 * The estimate is computed from count-min-style row counts corrected by the min-hash samples retained in the matching
 * cells. Bounds are approximate normal-style bounds over the retained identifier sample and are intentionally exposed
 * with the same 1/2/3 standard-deviation shape used by other DataSketches APIs.
 * </p>
 */
public final class OmniSketchEstimate {
	private final double estimate;
	private final double samplingProbability;
	private final int retainedEntries;
	private final int sampleIntersectionSize;
	private final long minRowCount;
	private final long maxRowCount;
	private final OmniSketchSummary summary;

	private OmniSketchEstimate(final double estimate, final double samplingProbability, final int retainedEntries,
			final int sampleIntersectionSize, final long minRowCount, final long maxRowCount,
			final OmniSketchSummary summary) {
		this.estimate = Math.max(0.0, estimate);
		this.samplingProbability = Math.max(0.0, Math.min(1.0, samplingProbability));
		this.retainedEntries = Math.max(0, retainedEntries);
		this.sampleIntersectionSize = Math.max(0, sampleIntersectionSize);
		this.minRowCount = Math.max(0L, minRowCount);
		this.maxRowCount = Math.max(0L, maxRowCount);
		this.summary = summary;
	}

	static OmniSketchEstimate of(final double estimate, final double samplingProbability, final int retainedEntries,
			final int sampleIntersectionSize, final long minRowCount, final long maxRowCount,
			final OmniSketchSummary summary) {
		return new OmniSketchEstimate(estimate, samplingProbability, retainedEntries, sampleIntersectionSize,
				minRowCount,
				maxRowCount, summary);
	}

	/** Returns the cardinality estimate. */
	public double getEstimate() {
		return estimate;
	}

	/** Returns an approximate lower bound using 1, 2, or 3 standard deviations. */
	public double getLowerBound(final int numStdDevs) {
		checkNumStdDevs(numStdDevs);
		return Math.max(0.0, estimate - numStdDevs * standardError());
	}

	/** Returns an approximate upper bound using 1, 2, or 3 standard deviations. */
	public double getUpperBound(final int numStdDevs) {
		checkNumStdDevs(numStdDevs);
		return estimate + numStdDevs * standardError();
	}

	/** Returns the effective sampling probability used by the estimate. */
	public double getSamplingProbability() {
		return samplingProbability;
	}

	/** Returns the number of retained hashes in the query summary. */
	public int getRetainedEntries() {
		return retainedEntries;
	}

	/** Returns the number of retained identifier hashes common to every queried cell or summary. */
	public int getSampleIntersectionSize() {
		return sampleIntersectionSize;
	}

	/** Returns the smallest raw row count observed while answering the query. */
	public long getMinRowCount() {
		return minRowCount;
	}

	/** Returns the largest raw row count observed while answering the query. */
	public long getMaxRowCount() {
		return maxRowCount;
	}

	/** Returns true when the estimate is zero. */
	public boolean isEmpty() {
		return estimate == 0.0;
	}

	OmniSketchSummary summary() {
		return summary;
	}

	private double standardError() {
		if (estimate == 0.0) {
			return 0.0;
		}
		if (samplingProbability <= 0.0) {
			return Math.sqrt(estimate);
		}
		if (samplingProbability >= 1.0) {
			return 0.0;
		}
		return Math.sqrt(estimate * (1.0 - samplingProbability) / samplingProbability);
	}

	private static void checkNumStdDevs(final int numStdDevs) {
		if (numStdDevs < 1 || numStdDevs > 3) {
			throw new SketchesArgumentException("numStdDevs must be 1, 2, or 3");
		}
	}

	@Override
	public String toString() {
		return "OmniSketchEstimate{" + "estimate=" + estimate + ", retainedEntries=" + retainedEntries
				+ ", sampleIntersectionSize=" + sampleIntersectionSize + ", minRowCount=" + minRowCount
				+ ", maxRowCount=" + maxRowCount + '}';
	}
}
